```ts
export type Locale = 'ru' | 'en';
export type TranslationMessages = Record<string, string | Record<string, string>>;
export type Translations = Record<Locale, TranslationMessages>;
export type TranslationParams = Record<string, string | number>;
export type TranslateFunction = (key: string, params?: TranslationParams) => string;
export interface I18nContextValue {
  locale: Locale;
  setLocale: (locale: Locale) => void;
  t: TranslateFunction;
}
```

**packages/@rkr-react/i18n/src/I18nProvider.tsx:**
```tsx
'use client';
import { createContext, useCallback, useMemo, useState } from 'react';
import type { ReactNode } from 'react';
import type { I18nContextValue, Locale, Translations } from './types';
import { getNestedValue, interpolate } from './utils';

export const I18nContext = createContext<I18nContextValue | null>(null);

export interface I18nProviderProps {
  locale?: Locale;
  messages: Translations;
  fallbackLocale?: Locale;
  children: ReactNode;
}

export function I18nProvider({
  locale: initialLocale = 'ru',
  messages,
  fallbackLocale = 'ru',
  children,
}: I18nProviderProps) {
  const [locale, setLocale] = useState<Locale>(initialLocale);
  const t = useCallback(
    (key: string, params?: Record<string, string | number>): string => {
      const currentMessages = messages[locale];
      if (currentMessages) {
        const value = getNestedValue(currentMessages, key);
        if (value !== key) return params ? interpolate(value, params) : value;
      }
      if (locale !== fallbackLocale) {
        const fallbackMessages = messages[fallbackLocale];
        if (fallbackMessages) {
          const value = getNestedValue(fallbackMessages, key);
          if (value !== key) return params ? interpolate(value, params) : value;
        }
      }
      return key;
    },
    [locale, messages, fallbackLocale],
  );
  const contextValue = useMemo<I18nContextValue>(() => ({ locale, setLocale, t }), [locale, t]);
  return <I18nContext value={contextValue}>{children}</I18nContext>;
}
```

**packages/@rkr-react/i18n/src/useTranslation.ts:**
```ts
'use client';
import { use } from 'react';
import { I18nContext } from './I18nProvider';
import { ru } from './locales/ru';
import type { I18nContextValue, TranslateFunction } from './types';
import { getNestedValue, interpolate } from './utils';

const FALLBACK_T: TranslateFunction = (key, params?) => {
  const value = getNestedValue(ru, key);
  if (value !== key) return params ? interpolate(value, params) : value;
  return key;
};

const DEFAULT_CONTEXT: I18nContextValue = {
  locale: 'ru',
  setLocale: () => { /* warns in dev */ },
  t: FALLBACK_T,
};

export function useTranslation(): I18nContextValue {
  const context = use(I18nContext);
  return context ?? DEFAULT_CONTEXT;
}
```

**Locale files:** en.ts and ru.ts have translations for: button, input, modal, combobox, pagination, table, fileInput, datePicker, timePicker, colorPicker, multiselect, otp, switch, rating, notify, steps, carousel, form, validation, devtools, common.

**Package exports in package.json:**
- `@rkr-react/i18n` -- main entry (I18nProvider, useTranslation, types, utils)
- `@rkr-react/i18n/locales/ru` -- Russian locale
- `@rkr-react/i18n/locales/en` -- English locale

